package gui; import dao.ClientDAO; import model.Client; import model.ClientTableModel; import javax.swing.*; import java.awt.*; import java.util.List; public class ClientForm extends JFrame { String role; int userId; JTable table; ClientDAO dao = new ClientDAO(); ClientTableModel model; public ClientForm(String role, int userId) { this.role = role; this.userId = userId; setTitle(role.equals("CLIENT") ? "My Account" : "Clients"); setExtendedState(JFrame.MAXIMIZED_BOTH); setLayout(new BorderLayout()); JLabel header = new JLabel( role.equals("CLIENT") ? "MY ACCOUNT" : "CLIENT MANAGEMENT", SwingConstants.CENTER ); header.setFont(new Font("Arial", Font.BOLD, 26)); header.setOpaque(true); header.setBackground(new Color(46, 204, 113)); header.setForeground(Color.WHITE); add(header, BorderLayout.NORTH); model = new ClientTableModel(getData()); table = new JTable(model); add(new JScrollPane(table), BorderLayout.CENTER); setVisible(true); } private List<Client> getData() { if (role.equals("ADMIN")) { return dao.getAll(); } if (role.equals("CLIENT")) { Client c = dao.getById(userId); if (c != null) { return java.util.Collections.singletonList(c); } } return java.util.Collections.emptyList(); } }
